#include <bits/stdc++.h>
using namespace std;

class MaxHeap {
public:
    vector<int> heap;

    // Function to insert a new element into the max-heap
    void insert(int value) {
        heap.push_back(value); // Add the new element at the end
        heapifyUp(heap.size() - 1); // Restore max-heap property
    }

    // Function to remove the maximum element (root) from the max-heap
    void removeMax() {
        if (heap.empty()) return;

        // Swap the root with the last element
        heap[0] = heap.back();
        heap.pop_back(); // Remove the last element

        // Restore max-heap property
        heapifyDown(0);
    }

    // Function to get the maximum element (root) of the max-heap
    int getMax() {
        if (heap.empty()) return -1; // Indicating heap is empty
        return heap[0];
    }

private:
    // Function to maintain the max-heap property by moving the element up
    void heapifyUp(int index) {
        while (index > 0) {
            int parentIndex = (index - 1) / 2;
            if (heap[index] > heap[parentIndex]) {
                swap(heap[index], heap[parentIndex]);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    // Function to maintain the max-heap property by moving the element down
    void heapifyDown(int index) {
        int size = heap.size();
        int largest = index;
        int leftChild = 2 * index + 1;
        int rightChild = 2 * index + 2;

        if (leftChild < size && heap[leftChild] > heap[largest]) {
            largest = leftChild;
        }
        if (rightChild < size && heap[rightChild] > heap[largest]) {
            largest = rightChild;
        }
        if (largest != index) {
            swap(heap[index], heap[largest]);
            heapifyDown(largest); // Recursively heapify the affected subtree
        }
    }
};

