#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *arr;
    int size;
    int capacity;
} MaxHeap;

// Function to create a max heap
MaxHeap* createMaxHeap(int capacity) {
    MaxHeap* maxHeap = (MaxHeap*)malloc(sizeof(MaxHeap));
    maxHeap->capacity = capacity;
    maxHeap->size = 0;
    maxHeap->arr = (int*)malloc(capacity * sizeof(int));
    return maxHeap;
}

// Function to swap two elements
void swap(int* a, int* b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

// Function to heapify up
void heapifyUp(MaxHeap* maxHeap, int index) {
    while (index > 0 && maxHeap->arr[index] > maxHeap->arr[(index - 1) / 2]) {
        swap(&maxHeap->arr[index], &maxHeap->arr[(index - 1) / 2]);
        index = (index - 1) / 2;
    }
}

// Function to insert an element into the max heap
void insert(MaxHeap* maxHeap, int value) {
    if (maxHeap->size == maxHeap->capacity) {
        printf("Heap is full. Cannot insert %d\n", value);
        return;
    }
    maxHeap->arr[maxHeap->size] = value;
    maxHeap->size++;
    heapifyUp(maxHeap, maxHeap->size - 1);
}

// Function to heapify down
void heapifyDown(MaxHeap* maxHeap, int index) {
    int largest = index;
    int leftChild = 2 * index + 1;
    int rightChild = 2 * index + 2;

    if (leftChild < maxHeap->size && maxHeap->arr[leftChild] > maxHeap->arr[largest]) {
        largest = leftChild;
    }
    if (rightChild < maxHeap->size && maxHeap->arr[rightChild] > maxHeap->arr[largest]) {
        largest = rightChild;
    }
    if (largest != index) {
        swap(&maxHeap->arr[index], &maxHeap->arr[largest]);
        heapifyDown(maxHeap, largest);
    }
}

// Function to delete the maximum element from the max heap
void deleteMax(MaxHeap* maxHeap) {
    if (maxHeap->size == 0) {
        return; // Heap is empty
    }
    // Replace the root with the last element
    maxHeap->arr[0] = maxHeap->arr[maxHeap->size - 1];
    maxHeap->size--;
    heapifyDown(maxHeap, 0);
}

// Function to get the maximum element
int getMax(MaxHeap* maxHeap) {
    return maxHeap->size > 0 ? maxHeap->arr[0] : -1;
}

// Main function
int main() {
    int N;
    scanf("%d", &N);

    MaxHeap* maxHeap = createMaxHeap(N);

    for (int i = 0; i < N; i++) {
        char query[2];
        int value;
        scanf("%s", query);

        if (query[0] == '+') {
            scanf("%d", &value);
            insert(maxHeap, value);
        } else if (query[0] == '-') {
            deleteMax(maxHeap);
        }

        // Print the current maximum element
        int currentMax = getMax(maxHeap);
        printf("%d\n", currentMax);
    }

    // Free allocated memory
    free(maxHeap->arr);
    free(maxHeap);

    return 0;
}

