import java.util.*;

class MaxHeap {
    private List<Integer> heap;

    public MaxHeap() {
        heap = new ArrayList<>();
    }

    // Function to insert a new element into the max-heap
    public void insert(int value) {
        heap.add(value); // Add the new element at the end
        heapifyUp(heap.size() - 1); // Restore max-heap property
    }

    // Function to remove the maximum element (root) from the max-heap
    public void removeMax() {
        if (heap.isEmpty()) return;

        // Swap the root with the last element
        heap.set(0, heap.get(heap.size() - 1));
        heap.remove(heap.size() - 1); // Remove the last element

        // Restore max-heap property
        if (!heap.isEmpty()) {
            heapifyDown(0);
        }
    }

    // Function to get the maximum element (root) of the max-heap
    public int getMax() {
        return heap.isEmpty() ? -1 : heap.get(0);
    }

    // Function to maintain the max-heap property by moving the element up
    private void heapifyUp(int index) {
        while (index > 0) {
            int parentIndex = (index - 1) / 2;
            if (heap.get(index) > heap.get(parentIndex)) {
                // Swap
                int temp = heap.get(index);
                heap.set(index, heap.get(parentIndex));
                heap.set(parentIndex, temp);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    // Function to maintain the max-heap property by moving the element down
    private void heapifyDown(int index) {
        int largest = index;
        int leftChild = 2 * index + 1;
        int rightChild = 2 * index + 2;
        int size = heap.size();

        if (leftChild < size && heap.get(leftChild) > heap.get(largest)) {
            largest = leftChild;
        }
        if (rightChild < size && heap.get(rightChild) > heap.get(largest)) {
            largest = rightChild;
        }
        if (largest != index) {
            // Swap
            int temp = heap.get(index);
            heap.set(index, heap.get(largest));
            heap.set(largest, temp);
            heapifyDown(largest); // Recursively heapify the affected subtree
        }
    }
}

