class MaxHeap {
    constructor() {
        this.heap = [];
    }

    // Function to insert a new element into the max-heap
    insert(value) {
        // Add the new value (negative to simulate max-heap)
        this.heap.push(-value);
        this.heapifyUp(this.heap.length - 1);
    }

    // Function to remove the maximum element (root) from the max-heap
    removeMax() {
        if (this.heap.length === 0) return;

        // Swap the root with the last element
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop(); // Remove the last element

        // Restore max-heap property
        this.heapifyDown(0);
    }

    // Function to get the maximum element (root) of the max-heap
    getMax() {
        return this.heap.length === 0 ? -1 : -this.heap[0]; // Return -1 if heap is empty
    }

    // Function to maintain the max-heap property by moving the element up
    heapifyUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[index] < this.heap[parentIndex]) {
                // Swap if current element is smaller than parent
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    // Function to maintain the max-heap property by moving the element down
    heapifyDown(index) {
        const size = this.heap.length;
        let largest = index;
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;

        if (leftChild < size && this.heap[leftChild] < this.heap[largest]) {
            largest = leftChild;
        }
        if (rightChild < size && this.heap[rightChild] < this.heap[largest]) {
            largest = rightChild;
        }
        if (largest !== index) {
            // Swap and continue heapifying down
            [this.heap[index], this.heap[largest]] = [this.heap[largest], this.heap[index]];
            this.heapifyDown(largest);
        }
    }
}

